function safeUrl(value) {
  const clean = String(value || '').trim();
  if (!clean) return DEFAULT_REVIEW_LINK;
  return /^https?:\/\//i.test(clean) ? clean : `https://${clean}`;
}

function clampText(value, max = 80) {
  return String(value || '').replace(/\s+/g, ' ').trim().slice(0, max);
}

function mm(value) {
  const n = Number(value || 0);
  return n % 1 ? n.toFixed(1) : String(Math.round(n));
}

function inch(value) {
  return (Number(value || 0) / 25.4).toFixed(2);
}

function formatSize(size, templateId) {
  if (templateId === 'round') return `${mm(size.widthMm)} × ${mm(size.widthMm)} mm circle / ${inch(size.widthMm)} × ${inch(size.widthMm)} in`;
  return `${mm(size.widthMm)} × ${mm(size.heightMm)} mm / ${inch(size.widthMm)} × ${inch(size.heightMm)} in`;
}

function fileName(name, suffix) {
  const base = clampText(name || 'sunrise-cafe', 48).toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '') || 'sunrise-cafe';
  return `${base}-${suffix}`;
}

function loadImage(src) {
  return new Promise((resolve) => {
    if (!src) { resolve(null); return; }
    const img = new Image();
    img.onload = () => resolve(img);
    img.onerror = () => resolve(null);
    img.src = src;
  });
}

function roundedRect(ctx, x, y, w, h, r) {
  const radius = Math.max(0, Math.min(r, w / 2, h / 2));
  ctx.beginPath();
  ctx.moveTo(x + radius, y);
  ctx.arcTo(x + w, y, x + w, y + h, radius);
  ctx.arcTo(x + w, y + h, x, y + h, radius);
  ctx.arcTo(x, y + h, x, y, radius);
  ctx.arcTo(x, y, x + w, y, radius);
  ctx.closePath();
}

function fitText(ctx, text, maxWidth, start, min, family = 'Inter, Arial', weight = 800) {
  let size = start;
  const value = clampText(text, 70);
  while (size > min) {
    ctx.font = `${weight} ${size}px ${family}`;
    if (ctx.measureText(value).width <= maxWidth) break;
    size -= 1;
  }
  return size;
}

function drawText(ctx, text, x, y, maxWidth, start, min, opts = {}) {
  const weight = opts.weight || 800;
  const family = opts.family || 'Inter, Arial, sans-serif';
  const value = clampText(text, opts.max || 70);
  const size = fitText(ctx, value, maxWidth, start, min, family, weight);
  ctx.save();
  ctx.font = `${weight} ${size}px ${family}`;
  ctx.fillStyle = opts.color || '#111827';
  ctx.textAlign = opts.align || 'center';
  ctx.textBaseline = 'middle';
  ctx.fillText(value, x, y);
  ctx.restore();
}

function drawGoogle(ctx, x, y, size) {
  const letters = [['G', '#4285f4'], ['o', '#ea4335'], ['o', '#fbbc05'], ['g', '#4285f4'], ['l', '#34a853'], ['e', '#ea4335']];
  ctx.save();
  ctx.font = `900 ${size}px Arial, sans-serif`;
  ctx.textBaseline = 'middle';
  const widths = letters.map(([l]) => ctx.measureText(l).width);
  const gap = size * 0.03;
  const total = widths.reduce((a, b) => a + b, 0) + gap * (letters.length - 1);
  let cursor = x - total / 2;
  letters.forEach(([letter, color], i) => {
    ctx.fillStyle = color;
    ctx.fillText(letter, cursor, y);
    cursor += widths[i] + gap;
  });
  ctx.restore();
}

function drawStars(ctx, x, y, size, color = '#f6a400') {
  ctx.save();
  ctx.font = `900 ${size}px Arial, sans-serif`;
  ctx.fillStyle = color;
  ctx.textAlign = 'center';
  ctx.textBaseline = 'middle';
  ctx.fillText('★★★★★', x, y);
  ctx.restore();
}

function drawSunriseLogo(ctx, x, y, size, logoImg, accent = '#ff4d16') {
  ctx.save();
  ctx.shadowColor = 'rgba(15,23,42,.18)';
  ctx.shadowBlur = size * 0.12;
  ctx.fillStyle = '#fff';
  ctx.beginPath();
  ctx.arc(x, y, size / 2, 0, Math.PI * 2);
  ctx.fill();
  ctx.shadowBlur = 0;
  ctx.lineWidth = Math.max(2, size * 0.035);
  ctx.strokeStyle = accent;
  ctx.stroke();
  if (logoImg) {
    const pad = size * 0.18;
    const ratio = Math.min((size - pad * 2) / logoImg.width, (size - pad * 2) / logoImg.height);
    const dw = logoImg.width * ratio;
    const dh = logoImg.height * ratio;
    ctx.save();
    ctx.beginPath();
    ctx.arc(x, y, size / 2 - pad * 0.4, 0, Math.PI * 2);
    ctx.clip();
    ctx.drawImage(logoImg, x - dw / 2, y - dh / 2, dw, dh);
    ctx.restore();
  } else {
    ctx.fillStyle = accent;
    ctx.beginPath();
    ctx.arc(x, y - size * 0.08, size * 0.17, Math.PI, 0);
    ctx.fill();
    ctx.lineWidth = Math.max(1.4, size * 0.045);
    ctx.strokeStyle = accent;
    for (let i = -3; i <= 3; i += 1) {
      const a = (-90 + i * 15) * Math.PI / 180;
      ctx.beginPath();
      ctx.moveTo(x + Math.cos(a) * size * 0.26, y - size * 0.08 + Math.sin(a) * size * 0.26);
      ctx.lineTo(x + Math.cos(a) * size * 0.38, y - size * 0.08 + Math.sin(a) * size * 0.38);
      ctx.stroke();
    }
    ctx.fillStyle = '#7c2d12';
    ctx.font = `900 ${Math.max(8, size * 0.11)}px Arial`;
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';
    ctx.fillText('SUNRISE', x, y + size * 0.24);
    ctx.fillText('CAFE', x, y + size * 0.36);
  }
  ctx.restore();
}

function drawQr(ctx, qrImg, logoImg, x, y, size, accent) {
  ctx.save();
  ctx.fillStyle = '#fff';
  ctx.shadowColor = 'rgba(15, 23, 42, .14)';
  ctx.shadowBlur = size * 0.075;
  roundedRect(ctx, x - size * 0.04, y - size * 0.04, size * 1.08, size * 1.08, size * 0.06);
  ctx.fill();
  ctx.shadowBlur = 0;
  if (qrImg) ctx.drawImage(qrImg, x, y, size, size);
  if (logoImg) drawSunriseLogo(ctx, x + size / 2, y + size / 2, size * 0.38, logoImg, accent);
  ctx.restore();
}

function drawTemplate(ctx, canvas, templateId, size, data) {
  const w = Math.max(240, Math.round(size.widthMm * PX_PER_MM * CANVAS_SCALE));
  const h = Math.max(240, Math.round(size.heightMm * PX_PER_MM * CANVAS_SCALE));
  canvas.width = w;
  canvas.height = h;
  ctx.clearRect(0, 0, w, h);
  const min = Math.min(w, h);
  const accent = templateId === 'beige' ? '#d7a33b' : '#ff4d16';
  const blue = '#139be8';
  const text = data.textColor || '#0f172a';

  if (templateId === 'round') {
    ctx.save();
    ctx.beginPath();
    ctx.arc(w / 2, h / 2, min * 0.486, 0, Math.PI * 2);
    ctx.clip();
    const bg = ctx.createLinearGradient(0, 0, w, h);
    bg.addColorStop(0, '#fffefb');
    bg.addColorStop(1, '#fffaf0');
    ctx.fillStyle = bg;
    ctx.fillRect(0, 0, w, h);
    ctx.strokeStyle = '#e7b85a'; ctx.lineWidth = min * 0.018;
    ctx.beginPath(); ctx.arc(w / 2, h / 2, min * 0.472, 0, Math.PI * 2); ctx.stroke();
    drawSunriseLogo(ctx, w/2, h*0.16, min*0.15, data.logoImg, accent);
    drawText(ctx, data.businessName, w/2, h*0.29, w*.66, min*.069, min*.038, { color:'#8b2d16', family:'Georgia, serif', max:34 });
    drawText(ctx, data.headline, w/2, h*.39, w*.62, min*.047, min*.03, { color:text, weight:750, max:38 });
    drawGoogle(ctx, w/2, h*.48, min*.098);
    drawStars(ctx, w/2, h*.555, min*.043, data.starColor);
    const qr = min*.26;
    drawQr(ctx, data.qrImg, data.logoImg, (w-qr)/2, h*.62, qr, accent);
    ctx.restore();
    return;
  }

  if (templateId === 'credit') {
    const bg = ctx.createLinearGradient(0, 0, w, h);
    bg.addColorStop(0, '#111827'); bg.addColorStop(.5, '#030712'); bg.addColorStop(1, '#2b170c');
    ctx.fillStyle = bg; ctx.fillRect(0,0,w,h);
    ctx.globalAlpha = .18; ctx.fillStyle = '#f59e0b'; ctx.beginPath(); ctx.arc(w*.86,h*.1,min*.34,0,Math.PI*2); ctx.fill(); ctx.globalAlpha=1;
    roundedRect(ctx, min*.07, min*.07, w-min*.14, h-min*.14, min*.06); ctx.lineWidth = min*.012; ctx.strokeStyle='rgba(251,191,36,.75)'; ctx.stroke();
    drawSunriseLogo(ctx,w/2,h*.105,min*.16,data.logoImg,accent);
    drawText(ctx, data.businessName, w/2, h*.22, w*.72, min*.068, min*.036, { color:'#fbd17b', family:'Georgia, serif', max:32 });
    drawText(ctx, 'Tap or Scan', w/2, h*.34, w*.7, min*.066, min*.036, { color:'#fff', weight:900 });
    drawText(ctx, 'to review us on', w/2, h*.405, w*.72, min*.035, min*.022, { color:'#cbd5e1', weight:700 });
    drawGoogle(ctx, w/2, h*.482, min*.11);
    drawStars(ctx, w/2, h*.555, min*.047, data.starColor);
    const qr = min*.47;
    drawQr(ctx, data.qrImg, data.logoImg, (w-qr)/2, h*.61, qr, accent);
    return;
  }

  const bg = ctx.createLinearGradient(0,0,w,h);
  if (templateId === 'beige') { bg.addColorStop(0,'#fff9ef'); bg.addColorStop(.56,'#fff4dd'); bg.addColorStop(1,'#f2d39d'); }
  else { bg.addColorStop(0,'#ffffff'); bg.addColorStop(.62,'#fffdf8'); bg.addColorStop(1,'#f8e4bc'); }
  ctx.fillStyle = bg; ctx.fillRect(0,0,w,h);
  ctx.globalAlpha = .12; ctx.fillStyle = accent; ctx.beginPath(); ctx.arc(w*.86,h*.1,min*.32,0,Math.PI*2); ctx.fill(); ctx.globalAlpha=1;
  const pad = min*.055;
  roundedRect(ctx, pad, pad, w-pad*2, h-pad*2, min*.035);
  ctx.strokeStyle = templateId === 'beige' ? '#d4a044' : '#f0b044'; ctx.lineWidth = min*.011; ctx.stroke();
  roundedRect(ctx, pad+min*.024, pad+min*.024, w-(pad+min*.024)*2, h-(pad+min*.024)*2, min*.026);
  ctx.strokeStyle='rgba(255,255,255,.68)'; ctx.lineWidth=min*.004; ctx.stroke();
  drawSunriseLogo(ctx,w/2,h*.105,min*.15,data.logoImg,accent);
  drawText(ctx, data.businessName, w/2, h*.215, w*.74, min*.084, min*.046, { color:'#8b2d16', family:'Georgia, serif', max:36 });
  ctx.strokeStyle = templateId === 'beige' ? '#d4a044' : '#f0b044'; ctx.lineWidth = min*.004; ctx.beginPath(); ctx.moveTo(w*.3,h*.267); ctx.lineTo(w*.7,h*.267); ctx.stroke();
  drawText(ctx, data.headline, w/2, h*.35, w*.74, min*.061, min*.034, { color:text, weight:750, max:40 });
  drawGoogle(ctx, w/2, h*.438, min*.116);
  drawStars(ctx, w/2, h*.525, min*.052, data.starColor);
  const qr = min*.415;
  const qrY = h*.588;
  drawQr(ctx, data.qrImg, data.logoImg, (w-qr)/2, qrY, qr, accent);
  const ctaW = w*.69, ctaH = min*.065, ctaY = Math.min(h*.925, qrY + qr + min*.07);
  const cta = ctx.createLinearGradient((w-ctaW)/2,ctaY,(w+ctaW)/2,ctaY);
  cta.addColorStop(0, blue); cta.addColorStop(1, '#087ed5');
  ctx.fillStyle = cta; roundedRect(ctx,(w-ctaW)/2,ctaY,ctaW,ctaH,min*.018); ctx.fill();
  drawText(ctx, data.subText, w/2, ctaY+ctaH/2, ctaW*.86, min*.026, min*.017, { color:'#fff', weight:850, max:36 });
}

function dataUrlToBytes(dataUrl) {
  const binary = atob((dataUrl.split(',')[1] || ''));
  const bytes = new Uint8Array(binary.length);
  for (let i = 0; i < binary.length; i += 1) bytes[i] = binary.charCodeAt(i);
  return bytes;
}

function pdfBlobFromCanvas(canvas, size) {
  const imageBytes = dataUrlToBytes(canvas.toDataURL('image/jpeg', .96));
  const pageW = (size.widthMm * 72) / 25.4;
  const pageH = (size.heightMm * 72) / 25.4;
  const enc = new TextEncoder(); const chunks = []; const offsets = [0]; let offset = 0;
  const add = (t) => { const b = enc.encode(t); chunks.push(b); offset += b.length; };
  const addBytes = (b) => { chunks.push(b); offset += b.length; };
  const obj = (n) => { offsets[n] = offset; add(`${n} 0 obj\n`); };
  add('%PDF-1.4\n');
  obj(1); add('<< /Type /Catalog /Pages 2 0 R >>\nendobj\n');
  obj(2); add('<< /Type /Pages /Kids [3 0 R] /Count 1 >>\nendobj\n');
  obj(3); add(`<< /Type /Page /Parent 2 0 R /MediaBox [0 0 ${pageW.toFixed(2)} ${pageH.toFixed(2)}] /Resources << /XObject << /Im0 4 0 R >> >> /Contents 5 0 R >>\nendobj\n`);
  obj(4); add(`<< /Type /XObject /Subtype /Image /Width ${canvas.width} /Height ${canvas.height} /ColorSpace /DeviceRGB /BitsPerComponent 8 /Filter /DCTDecode /Length ${imageBytes.length} >>\nstream\n`); addBytes(imageBytes); add('\nendstream\nendobj\n');
  const content = `q\n${pageW.toFixed(2)} 0 0 ${pageH.toFixed(2)} 0 0 cm\n/Im0 Do\nQ\n`;
  obj(5); add(`<< /Length ${enc.encode(content).length} >>\nstream\n${content}endstream\nendobj\n`);
  const xref = offset; add('xref\n0 6\n0000000000 65535 f \n'); for (let i=1;i<=5;i+=1) add(`${String(offsets[i]).padStart(10,'0')} 00000 n \n`);
  add(`trailer\n<< /Size 6 /Root 1 0 R >>\nstartxref\n${xref}\n%%EOF`);
  return new Blob(chunks, { type: 'application/pdf' });
}

function downloadBlob(blob, name) {
  const url = URL.createObjectURL(blob); const a = document.createElement('a'); a.href = url; a.download = name; document.body.appendChild(a); a.click(); a.remove(); setTimeout(() => URL.revokeObjectURL(url), 1200);
}

function downloadDataUrl(dataUrl, name) { const a = document.createElement('a'); a.href = dataUrl; a.download = name; document.body.appendChild(a); a.click(); a.remove(); }

